function Write-Output {
    param([string]$Message, [string]$Level = 'Info')
    if ($ShowOutput) {
        $prefix = switch ($Level) {
            'Success' { '✅' }
            'Warning' { '⚠️' }
            'Error' { '❌' }
            'Info' { 'ℹ️' }
            default { '  ' }
        }
        Write-Host "$prefix $Message"
    }
}

